insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:2-4-5-place:mcq:26dad39f', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "A small farmer selling organic strawberries from a roadside stall is using which distribution method?", "options": ["Digital Distribution", "Producer → Wholesaler → Retailer", "Producer → Retailer → Consumer", "Producer → Consumer (Direct Selling)"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. The farmer is the producer, and they are selling directly to the person who will eat the strawberries. This is Channel 1."}'::jsonb),
('business:2-4-5-place:mcq:5da7dd2e', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "What is an advantage to a small independent corner shop of using a wholesaler?", "options": ["They can buy huge factory-sized lorry loads of stock", "They can buy smaller, affordable quantities of various goods in one place", "The wholesaler will pay the corner shop''s rent", "The wholesaler will manufacture bespoke products for them"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A corner shop doesn''t have the money or space for a whole lorry of Coca-Cola. The wholesaler allows them to buy a few cases at a time alongside crisps, bread, etc."}'::jsonb),
('business:2-4-5-place:mcq:4fbca7cc', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Which of the following businesses relies entirely on physical distribution?", "options": ["Netflix", "Spotify", "A comparison website selling car insurance", "A bakery selling fresh bread"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Bread is a physical, tangible good that cannot be distributed over the internet."}'::jsonb),
('business:2-4-5-place:mcq:131ae0b8', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "One disadvantage to a clothing business (like Boohoo) of distributing purely through e-commerce is:", "options": ["Customers cannot try the clothes on before buying, leading to high return rates", "They have to pay massive rent for high-street shops in London", "They cannot accept credit card payments", "They are only open during normal daylight hours"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Without physical fitting rooms, online clothing retailers face massive logistical costs dealing with returned items that did not fit the customer."}'::jsonb),
('business:2-4-5-place:mcq:35d84ec6', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "What is a major financial benefit to a business of switching from physical high-street shops to purely digital e-commerce?", "options": ["They no longer have to pay for web servers", "They will automatically gain a 100% market share", "They drastically reduce overhead costs like shop rent and sales staff wages", "They no longer need to advertise their products"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. E-commerce avoids the massive fixed costs associated with physical retail premises on expensive high streets."}'::jsonb),
('business:2-4-5-place:tf:dfc8d5dc', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "In the marketing mix, ''Place'' refers only to the physical town where the factory is built."}'::jsonb, '{"answer": false, "explain": "FALSE. Place refers to Distribution Channels — how the product gets from the producer to the customer."}'::jsonb),
('business:2-4-5-place:tf:59f1c0a9', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "A major role of a wholesaler is to break bulk shipments into smaller quantities."}'::jsonb, '{"answer": true, "explain": "TRUE. Wholesalers buy in massive bulk from factories and break it down into affordable boxes for small retailers."}'::jsonb),
('business:2-4-5-place:tf:93896df0', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "Channel 1 (Direct Selling) involves a wholesaler and a retailer."}'::jsonb, '{"answer": false, "explain": "FALSE. Channel 1 is Producer directly to Consumer. There are no wholesalers or retailers involved."}'::jsonb),
('business:2-4-5-place:tf:ddcd34a3', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "Digital distribution allows a business to be open 24 hours a day, 7 days a week."}'::jsonb, '{"answer": true, "explain": "TRUE. E-commerce websites and digital downloads do not require staff to be awake, allowing 24/7 global sales."}'::jsonb),
('business:2-4-5-place:tf:97c8dc5c', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "A disadvantage of digital distribution is that it limits the business to only selling to people in their local town."}'::jsonb, '{"answer": false, "explain": "FALSE. Digital distribution does the exact opposite; it allows the business to sell globally to anyone with an internet connection."}'::jsonb),
('business:2-4-5-place:tf:fff454d3', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "Selling through a wholesaler means the producer has to accept a lower profit margin per item."}'::jsonb, '{"answer": true, "explain": "TRUE. The wholesaler is a business that needs to make money, so they take a cut of the profit, reducing the margin left for the producer."}'::jsonb),
('business:2-4-5-place:tf:fd736ddc', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "Piracy (illegal copying and sharing) is a major risk for businesses using digital distribution."}'::jsonb, '{"answer": true, "explain": "TRUE. Products like digital music, software, and eBooks can easily be duplicated and shared illegally online, losing the business revenue."}'::jsonb),
('business:2-4-5-place:tf:02c6392d', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "A small local farmer selling vegetables at a farm gate is using Physical Distribution Channel 3."}'::jsonb, '{"answer": false, "explain": "FALSE. They are selling directly to the consumer, which is Channel 1 (Producer to Consumer)."}'::jsonb),
('business:2-4-5-place:tf:42268611', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "One benefit of an online clothing store is that customers can easily try the clothes on before they pay."}'::jsonb, '{"answer": false, "explain": "FALSE. A major disadvantage of online retail is that customers CANNOT try items on beforehand, leading to high return rates."}'::jsonb),
('business:2-4-5-place:tf:420610bf', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "Using digital distribution cuts down on costs because the business does not need to pay for high-street shop rent."}'::jsonb, '{"answer": true, "explain": "TRUE. Removing physical retail premises massively reduces fixed overhead costs like rent and shop-floor staff wages."}'::jsonb),
('business:2-4-5-place:tf:7a426342', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "All products can be distributed digitally if the business upgrades its technology."}'::jsonb, '{"answer": false, "explain": "FALSE. Physical, tangible goods like fresh food, cars, and clothing cannot be distributed digitally; they must be physically transported."}'::jsonb),
('business:2-4-5-place:tf:626908e6', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tf', 'tf', 1, '{"question": "If a business sells online, it faces more intense competition because consumers can buy from anywhere in the world."}'::jsonb, '{"answer": true, "explain": "TRUE. While global reach is an advantage, the disadvantage is that you are now competing against every other similar business on the planet."}'::jsonb),
('business:2-4-5-place:learn:d09c5700', 'business', 'business:2-4-5-place', '2.4.5 Place', 'learn', 'mcq', 1, '{"readingTitle": "What is Place?", "reading": "<p><strong>Place</strong> in the marketing mix does not just mean the physical location of a shop. It refers to the <strong>channels of distribution</strong> — the methods used to get a product or service from the producer to the final consumer.</p>\n  <p>Distribution can be broadly split into two categories:</p>\n  <ul>\n  <li><strong>Physical Distribution:</strong> The movement of physical, tangible goods from the producer to the consumer (e.g., delivering a car, a loaf of bread, or a physical book).</li>\n  <li><strong>Digital Distribution:</strong> When a product or service is downloaded or streamed by the consumer directly from the seller via the internet (e.g., streaming music on Spotify, downloading software, or buying travel insurance online).</li>\n  </ul>\n  <p>With the rapid growth of e-commerce, the way products are distributed has changed dramatically, forcing traditional high-street businesses to adapt.</p>", "question": "In the marketing mix, what does ''Place'' actually refer to?", "options": ["The design and packaging of the product", "The physical location/address of the business''s shop", "The price charged for delivery to different regions", "The channels of distribution from producer to consumer"]}'::jsonb, '{"answer": 3, "explain": "The card explains that Place refers to the channels of distribution, not simply the physical location of a shop."}'::jsonb),
('business:2-4-5-place:learn:37bd0adf', 'business', 'business:2-4-5-place', '2.4.5 Place', 'learn', 'mcq', 1, '{"readingTitle": "Physical Distribution Channels", "reading": "<p>There are three main physical distribution channels a business can use:</p>\n  <ol>\n  <li><strong>Channel 1: Producer → Consumer (Direct Selling)</strong><br>\n  The product goes straight from the maker to the buyer. This is often used by small businesses (e.g., a small bakery, a farmer selling strawberries at a stall, or a bespoke furniture maker).<br>\n  <em>Advantage:</em> The producer keeps all the profit because there are no ''middlemen'' taking a cut.</li>\n  <li><strong>Channel 2: Producer → Retailer → Consumer</strong><br>\n  The producer sells in large quantities to a retailer (like Currys or B&Q), who then sells to the public. <br>\n  <em>Advantage:</em> The producer benefits from keeping the profit margin usually given to a wholesaler, whilst relying on the retailer''s massive footfall to sell the goods.</li>\n  <li><strong>Channel 3: Producer → Wholesaler → Retailer → Consumer</strong><br>\n  Used heavily for fast-moving consumer goods (e.g., corner shops buying chocolate and drinks). The producer sells massive quantities to a wholesaler (like Costco or Booker). The wholesaler then sells smaller boxes to independent retailers, who sell individual items to consumers.</li>\n  </ol>", "question": "Which distribution channel allows a producer to keep all the profit because there are no ''middlemen''?", "options": ["Channel 1: Producer → Consumer (Direct Selling)", "Channel 2: Producer → Retailer → Consumer", "Channel 3: Producer → Wholesaler → Retailer → Consumer", "A channel using an agent to negotiate contracts"]}'::jsonb, '{"answer": 0, "explain": "Channel 1 (direct selling) means the product goes straight from maker to buyer, so the producer keeps all the profit with no middlemen taking a cut."}'::jsonb),
('business:2-4-5-place:learn:d5737f24', 'business', 'business:2-4-5-place', '2.4.5 Place', 'learn', 'mcq', 1, '{"readingTitle": "The Role of the Wholesaler", "reading": "<p>A <strong>wholesaler</strong> acts as a vital link between massive producers and tiny independent retailers.</p>\n  <p>Their main job is to <strong>''break bulk''</strong>. A huge producer (like Coca-Cola) will not sell just one box of cans to a small local corner shop; they only sell by the lorry-load. The wholesaler buys the massive lorry-load (the bulk), stores it in a giant warehouse, and breaks it down into smaller, affordable boxes that a small retailer can afford to buy.</p>\n  <div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages to the Producer</div>\n  <div class=\"pro-item\">Saves warehousing costs because the wholesaler stores the massive stock.</div>\n  <div class=\"pro-item\">Guaranteed massive sales volumes in a single transaction.</div>\n  <div class=\"pro-item\">The wholesaler handles the logistics of delivering to thousands of small shops.</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages to the Producer</div>\n  <div class=\"con-item\">Profit margins are reduced because the wholesaler takes a cut of the profit.</div>\n  <div class=\"con-item\">Loss of control over how the product is displayed and marketed to the final consumer.</div>\n  </div>\n  </div>", "question": "What is the main role of a wholesaler, known as ''breaking bulk''?", "options": ["Splitting bulk purchases into smaller batches for retailers", "Storing goods for producers without ever selling them on", "Manufacturing products in bulk quantities for retailers", "Selling directly to the general public in bulk"]}'::jsonb, '{"answer": 0, "explain": "The card states the wholesaler''s main job is to ''break bulk'' by buying lorry-loads from producers and dividing them into smaller boxes small retailers can afford."}'::jsonb),
('business:2-4-5-place:learn:5011311f', 'business', 'business:2-4-5-place', '2.4.5 Place', 'learn', 'mcq', 1, '{"readingTitle": "Digital Distribution", "reading": "<p>Digital distribution allows products to be delivered electronically. This is suited to software, media (music/films), and services (insurance, banking).</p>\n  <div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages</div>\n  <div class=\"pro-item\">A business can sell globally, massively increasing potential customers.</div>\n  <div class=\"pro-item\">Can be open 24/7, all year round.</div>\n  <div class=\"pro-item\">Massive cost savings: no physical shop rent, less staff needed, and zero transport/delivery costs for digital files.</div>\n  <div class=\"pro-item\">Eco-friendly (no plastic packaging or diesel delivery lorries).</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages</div>\n  <div class=\"con-item\">Global reach means global competition; it is very hard to stand out.</div>\n  <div class=\"con-item\">Requires credit/debit cards, creating potential security/fraud issues that put off some consumers.</div>\n  <div class=\"con-item\">Massive initial and ongoing costs for building and maintaining a secure e-commerce website.</div>\n  <div class=\"con-item\"><strong>Piracy:</strong> Digital content can easily be copied and illegally shared for free online.</div>\n  </div>\n  </div>", "question": "Which of these is a genuine disadvantage of digital distribution for a business?", "options": ["Having to pay for physical packaging and diesel delivery lorries", "A smaller potential customer base than a single local shop", "The cost of building and maintaining a secure e-commerce website", "Being restricted to operating only during normal shop opening hours"]}'::jsonb, '{"answer": 2, "explain": "The card lists the massive initial and ongoing cost of building/maintaining a secure e-commerce website as a disadvantage, whereas 24/7 operation and global reach are actually advantages."}'::jsonb),
('business:2-4-5-place:learn:e9854c60', 'business', 'business:2-4-5-place', '2.4.5 Place', 'learn', 'mcq', 1, '{"readingTitle": "Case Studies: Morrisons, Amazon, and Sony", "reading": "<p><strong>Morrisons on Amazon (Physical Distribution Innovation):</strong><br>\n  Morrisons was late to the home-delivery market compared to Tesco. To catch up, they partnered with Amazon to offer ''Morrisons on Amazon''. This physical distribution uses Amazon''s massive logistics network to deliver groceries to Prime members on the same day. By emphasizing speed of delivery, they aim to pull customers away from rival supermarkets.</p>\n  <p><strong>Sony & Netflix (Digital Distribution Transition):</strong><br>\n  In the past, Sony physically distributed Elvis records on vinyl. Today, music and films are streamed. Netflix originally physically posted DVDs to customers. Now, it is a giant of digital distribution, streaming directly to TVs. This cuts out physical manufacturing costs entirely but forces them to battle illegal downloading (piracy) and intense competition from Disney+ and Amazon Prime.</p>", "question": "What change in distribution method did Netflix undergo over time?", "options": ["From digital streaming to physically posting DVDs to customers", "From being a wholesaler to becoming a direct retailer", "From selling music on vinyl to selling only through a wholesaler network", "From physically posting DVDs to customers, to digital streaming"]}'::jsonb, '{"answer": 3, "explain": "The case study explains Netflix originally physically posted DVDs and is now a giant of digital distribution, streaming directly to TVs."}'::jsonb),
('business:2-4-5-place:misc:10d20d88', 'business', 'business:2-4-5-place', '2.4.5 Place', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often write that ''Place'' means the location of the business (e.g. ''The shop is in London'').</p><p><strong>✅ The correct idea:</strong> In the marketing mix, Place specifically means DISTRIBUTION CHANNELS — the method/journey used to get the product to the consumer (e.g. e-commerce, wholesalers, direct selling).</p>", "question": "A student writes that ''Place'' means where the business''s shop is located. What is the accurate GCSE definition?", "options": ["The retail price charged in different regions", "The physical street address of the business''s premises", "The country where the business''s head office is based", "Distribution channels used to get the product to consumers"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the common misconception: Place means distribution channels (e.g. e-commerce, wholesalers, direct selling), not the location of the shop."}'::jsonb),
('business:2-4-5-place:misc:7d57d03c', 'business', 'business:2-4-5-place', '2.4.5 Place', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think wholesalers sell to the general public.</p><p><strong>✅ The correct idea:</strong> Wholesalers (like Booker) generally sell to other businesses (Retailers). Retailers (like Tesco or a corner shop) are the ones who sell to the general public (Consumers).</p>", "question": "Who do wholesalers typically sell to?", "options": ["Only to producers, never onward", "Directly to wholesalers based overseas", "Directly to the general public", "Other businesses, such as retailers"]}'::jsonb, '{"answer": 3, "explain": "The card clarifies that wholesalers generally sell to retailers (other businesses), while it is retailers who sell to the general public."}'::jsonb),
('business:2-4-5-place:misc:0dab06ee', 'business', 'business:2-4-5-place', '2.4.5 Place', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When answering ''disadvantages of online distribution for the CUSTOMER'', students write about website maintenance costs.</p><p><strong>✅ The correct idea:</strong> Always read the entity in the question. If it asks for a disadvantage to the CUSTOMER, write about inability to try things on, postage delays, or security fears. Website costs are a disadvantage to the BUSINESS.</p>", "question": "A question asks for a disadvantage of online shopping to the CUSTOMER. Which answer is actually creditworthy?", "options": ["Increased packaging and logistics costs for the business", "Inability to try clothes on before buying, risking wrong size", "Loss of control over in-store product displays", "The high cost of building and maintaining a secure website"]}'::jsonb, '{"answer": 1, "explain": "The card warns you must read the entity in the question — a disadvantage to the CUSTOMER means things like being unable to try items on, not website costs, which affect the BUSINESS."}'::jsonb),
('business:2-4-5-place:misc:05892506', 'business', 'business:2-4-5-place', '2.4.5 Place', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students state that selling directly to consumers (Channel 1) increases total sales volume for massive brands.</p><p><strong>✅ The correct idea:</strong> Actually, massive brands (like Coca-Cola) use wholesalers because they CANNOT physically distribute millions of single cans to individuals efficiently. Direct selling is usually best for smaller, bespoke, or service businesses.</p>", "question": "Why would a massive brand like Coca-Cola use wholesalers rather than selling directly to every individual consumer?", "options": ["Direct selling cannot efficiently distribute millions of units to consumers", "Direct selling is banned for businesses above a certain size", "Selling directly always generates a bigger total sales volume for large brands", "Wholesalers are legally required for all food and drink products"]}'::jsonb, '{"answer": 0, "explain": "The card explains massive brands cannot physically distribute millions of single units to individuals efficiently, so direct selling suits smaller, bespoke, or service businesses instead."}'::jsonb),
('business:2-4-5-place:tips:d1dcac27', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tips', 'mcq', 1, '{"readingTitle": "Key Term (1 mark) — Breaking Bulk", "reading": "<p>If asked to define the role of a wholesaler, always use the phrase <strong>''breaking bulk''</strong>.</p>\n  <p>This means buying in massive quantities directly from the factory and splitting it into smaller, manageable, affordable boxes for small independent retailers.</p>", "question": "When defining the role of a wholesaler for a 1-mark key term question, which key phrase should you use?", "options": ["''Breaking bulk''", "''Economies of scale''", "''Cutting the middleman''", "''Adding value''"]}'::jsonb, '{"answer": 0, "explain": "The card instructs students to always use the phrase ''breaking bulk'' when defining a wholesaler''s role."}'::jsonb),
('business:2-4-5-place:tips:73bd287c', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Impact on the Customer vs Business", "reading": "<p>Pay close attention to WHO the question is asking about.</p>\n  <p><strong>Impact on Customer:</strong> \"A disadvantage to the customer of Boohoo''s online distribution is that they cannot try the clothes on (U), meaning they might order the wrong size (APP) and have to suffer the inconvenience of returning it via post (AN).\"</p>\n  <p><strong>Impact on Business:</strong> \"A disadvantage to the business is that returns are high (U) for online clothing (APP), which severely increases logistics and repacking costs (AN).\"</p>", "question": "In the model answers, ''they cannot try the clothes on (U)... might order the wrong size (APP)...'', what does the ''APP'' label stand for?", "options": ["Application - applying the point to the business context", "Appraisal - evaluating whether the point is strong", "Approach - the general method used to answer the question", "Approval - the examiner''s approval of the point"]}'::jsonb, '{"answer": 0, "explain": "The card labels the specific reference to ordering the wrong size as (APP), meaning Application of the point to the exact scenario given."}'::jsonb),
('business:2-4-5-place:tips:902f1c3e', 'business', 'business:2-4-5-place', '2.4.5 Place', 'tips', 'mcq', 1, '{"readingTitle": "Recommend (3 marks) — Choosing a Channel", "reading": "<p>When asked to recommend a channel (e.g., direct vs wholesaler for Dulux paint), your justification MUST be comparative.</p>\n  <p><strong>Example:</strong> \"Dulux should sell to large retailers directly (1) because they keep a higher profit margin by cutting out the middleman, whereas selling to wholesalers means giving up a percentage of their profits (+2).\"</p>", "question": "When recommending a distribution channel for 3 marks (e.g., direct selling vs wholesaler for Dulux), what must your justification include?", "options": ["A list of every possible distribution channel available", "A comparison showing why the recommended option is better", "A definition of what a distribution channel is", "A description of the business''s history and background"]}'::jsonb, '{"answer": 1, "explain": "The card states the justification MUST be comparative, as shown by the Dulux example weighing direct selling against giving up profit to a wholesaler."}'::jsonb),
