('business:2-4-5-place:match:b5af7f7c', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Place”?", "options": ["The movement of tangible goods from the producer to the consumer using transport.", "Delivering products electronically over the internet, such as streaming music or software.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The specific route a product takes from the manufacturer to the end-user."]}'::jsonb, '{"answer": 2, "explain": "“Place” means: The part of the marketing mix concerned with the distribution channels used to get goods to customers."}'::jsonb),
('business:2-4-5-place:match:492e0983', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Physical Distribution”?", "options": ["Delivering products electronically over the internet, such as streaming music or software.", "The specific route a product takes from the manufacturer to the end-user.", "The movement of tangible goods from the producer to the consumer using transport.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers."]}'::jsonb, '{"answer": 2, "explain": "“Physical Distribution” means: The movement of tangible goods from the producer to the consumer using transport."}'::jsonb),
('business:2-4-5-place:match:7e29b9ac', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Digital Distribution”?", "options": ["The specific route a product takes from the manufacturer to the end-user.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "Delivering products electronically over the internet, such as streaming music or software."]}'::jsonb, '{"answer": 3, "explain": "“Digital Distribution” means: Delivering products electronically over the internet, such as streaming music or software."}'::jsonb),
('business:2-4-5-place:match:c6cff139', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Distribution Channel”?", "options": ["A business that buys in massive bulk from producers and sells smaller quantities to retailers.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "The specific route a product takes from the manufacturer to the end-user.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public."]}'::jsonb, '{"answer": 2, "explain": "“Distribution Channel” means: The specific route a product takes from the manufacturer to the end-user."}'::jsonb),
('business:2-4-5-place:match:4b67fee1', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wholesaler”?", "options": ["The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Consumer. Cuts out all middlemen.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers."]}'::jsonb, '{"answer": 3, "explain": "“Wholesaler” means: A business that buys in massive bulk from producers and sells smaller quantities to retailers."}'::jsonb),
('business:2-4-5-place:match:47657760', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Breaking Bulk”?", "options": ["A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Consumer. Cuts out all middlemen.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets."]}'::jsonb, '{"answer": 2, "explain": "“Breaking Bulk” means: The process of splitting massive factory shipments into smaller, affordable boxes for small shops."}'::jsonb),
('business:2-4-5-place:match:b6f60226', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retailer”?", "options": ["Producer → Consumer. Cuts out all middlemen.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution."]}'::jsonb, '{"answer": 1, "explain": "“Retailer” means: A business (like a supermarket or high-street shop) that sells goods directly to the general public."}'::jsonb),
('business:2-4-5-place:match:ce6a8efa', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Direct Selling (Channel 1)”?", "options": ["Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "Producer → Consumer. Cuts out all middlemen.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally."]}'::jsonb, '{"answer": 1, "explain": "“Direct Selling (Channel 1)” means: Producer → Consumer. Cuts out all middlemen."}'::jsonb),
('business:2-4-5-place:match:fcc9b822', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Channel 2”?", "options": ["Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer."]}'::jsonb, '{"answer": 0, "explain": "“Channel 2” means: Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets."}'::jsonb),
('business:2-4-5-place:match:f0c6a90b', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Piracy”?", "options": ["Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit."]}'::jsonb, '{"answer": 1, "explain": "“Piracy” means: The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution."}'::jsonb),
('business:2-4-5-place:match:9bb1a13f', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “E-commerce”?", "options": ["An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers."]}'::jsonb, '{"answer": 2, "explain": "“E-commerce” means: Buying and selling goods over the internet, which allows businesses to operate 24/7 globally."}'::jsonb),
('business:2-4-5-place:match:33727cb7', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Middleman”?", "options": ["An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The movement of tangible goods from the producer to the consumer using transport."]}'::jsonb, '{"answer": 0, "explain": "“Middleman” means: An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer."}'::jsonb),
('business:2-4-5-place:match:bf0cc3e6', 'business', 'business:2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Return logistics”?", "options": ["The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The movement of tangible goods from the producer to the consumer using transport.", "A major cost for online clothing retailers when customers send back items that do not fit.", "Delivering products electronically over the internet, such as streaming music or software."]}'::jsonb, '{"answer": 2, "explain": "“Return logistics” means: A major cost for online clothing retailers when customers send back items that do not fit."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:c50de794', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Market data includes:", "options": ["changes in the school curriculum", "changes in market demand", "changes in the number of factory workers", "changes in workers'' hourly pay"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Market data relates to external consumer and competitor behaviors, such as demand, market share, and sales trends."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:118b5aea', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Which of the following will NOT normally be helped by the use of market data?", "options": ["Decisions on whether to increase production output", "Decisions on what questions to ask a candidate at a job interview", "Decisions on whether to build a new factory", "Decisions on whether to start a television advertising campaign"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Job interviews are a Human Resources function. Market data is used for Marketing and Operational planning."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:94a4c783', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Market share is best defined as:", "options": ["the product''s share of the total marketing mix budget", "the amount of goods a business sells in a 12-month period", "the amount of goods a business sells as a percentage of the total market for a product", "the goods that a business sells as a percentage of its previous year''s sales"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Market share measures how dominant a business is compared to ALL other competitors in that specific market combined."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:192489f4', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "PQS Ltd makes computer printers. The total market for the printers is 550,000 items per year. PQS Ltd sells 40,000 printers per year. What is PQS Ltd''s market share?", "options": ["7.27%", "8.21%", "8.79%", "9.14%"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Formula: (Business Sales / Total Market Sales) x 100. (40,000 / 550,000) x 100 = 7.27%."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:170dc8bc', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "What does it mean to have an ''Integrated Marketing Mix''?", "options": ["The business only focuses on Product and Price.", "The 4 Ps all complement each other and send a consistent message to the target market.", "The business spends an equal amount of money on all 4 Ps.", "The business integrates its marketing department with the HR department."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Integration means the parts fit together—e.g., a high-quality product is sold at a premium price, in an exclusive place, with high-end promotion."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:4537393e', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "A business launches a highly premium, luxury perfume. It prices it at £150 a bottle, but sells it only in a budget discount supermarket. This is an example of:", "options": ["Price skimming", "A poor integrated marketing mix", "Excellent use of market data", "Digital distribution"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The ''Place'' (a discount supermarket) heavily conflicts with the ''Product'' (luxury) and ''Price'' (£150), confusing the consumer and leading to failure."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:d12e5de2', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "How did Nintendo ensure its ''Promotion'' integrated perfectly with its ''Product'' for the Nintendo Switch?", "options": ["They advertised it as the cheapest console on the market.", "They focused all advertisements on the portability of the system within social settings.", "They offered a free game with every purchase.", "They only sold it through digital distribution."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The core Product innovation was portability; the Promotion highlighted this exactly, ensuring the mix was perfectly integrated."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:969dd719', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Company X sells 5,000 units in Year 1. In Year 2, Company X sells 6,000 units. However, their market share DROPPED. How is this mathematically possible?", "options": ["They increased their prices.", "The total market size grew faster than Company X''s sales grew.", "They spent less on advertising.", "It is mathematically impossible."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. If Company X grows by 20%, but competitors grow by 50%, Company X''s slice of the overall ''pie'' becomes smaller, meaning market share drops."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:809a6f8a', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "A target market is defined as:", "options": ["A supermarket where target goods are sold.", "The financial sales goal a business wishes to hit.", "The specific group of consumers to whom the business tries to sell its products.", "The percentage increase in the size of the total market."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Every element of the integrated marketing mix must be designed to appeal to this specific target group."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:247cdb18', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "If a business decides to use digital distribution (Place), how might this logically affect its Pricing strategy?", "options": ["Prices must always be higher because of website costs.", "Prices can potentially be lower because physical overhead costs (rent, delivery) are reduced.", "Prices must use price skimming.", "Digital distribution has absolutely no effect on Price."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Because the 4 Ps are integrated, a change in Place (going digital = lower costs) allows the business flexibility to lower its Price."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:mcq:172b2a7e', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Before taking drastic action (like stopping production) due to a sudden drop in sales shown in market data, a business should:", "options": ["Immediately fire the marketing team.", "Double the price of the product.", "View the data against a longer-term trend to see if it is just a temporary dip.", "Switch completely to digital distribution."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Short-term data can be misleading (e.g., a bad month due to a competitor''s brief sale). Long-term trends are required for major business decisions."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:baf854c5', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market data helps a business decide what questions to ask a candidate at a job interview."}'::jsonb, '{"answer": false, "explain": "FALSE. Market data is used for marketing and production decisions, not HR/recruitment processes."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:a9252856', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market share is the amount of goods a business sells as a percentage of the total market for a product."}'::jsonb, '{"answer": true, "explain": "TRUE. It measures how much of the total market ''pie'' is controlled by one specific business."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:b5ed0ec7', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "If a company''s sales figures go up from one year to the next, their market share is guaranteed to go up as well."}'::jsonb, '{"answer": false, "explain": "FALSE. If the total market grows faster than the company''s sales (e.g., competitors are selling even more), the company''s market share will actually fall."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:d166fe7e', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "An integrated marketing mix means all 4 Ps work together and send a consistent message to the target market."}'::jsonb, '{"answer": true, "explain": "TRUE. The product, price, place, and promotion must all logically align. You cannot have a luxury price for a budget product in a discount store."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:b2bcc7fe', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "The Nintendo Switch used penetration pricing at launch because it was a cheap, basic console."}'::jsonb, '{"answer": false, "explain": "FALSE. Nintendo used Price Skimming (£279.99) because the Switch was a highly innovative, unique product."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:cb2eebb2', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "A poor marketing mix would be selling a highly priced luxury item on a basic, unsecure website."}'::jsonb, '{"answer": true, "explain": "TRUE. The premium Price and premium Product conflict directly with the poor-quality Place (distribution channel), which will deter customers."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:614ce0f1', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Using penetration pricing is a guaranteed way to make a large profit immediately."}'::jsonb, '{"answer": false, "explain": "FALSE. Penetration pricing involves setting artificially low prices. It sacrifices short-term profit to gain market share quickly."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:b0842207', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market growth compares the original size of a market to the new size of the market to find a percentage increase."}'::jsonb, '{"answer": true, "explain": "TRUE. The formula is: ((New Market Size - Original Size) / Original Size) * 100."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:003ea873', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market data is useless for a small business like a local market stall."}'::jsonb, '{"answer": false, "explain": "FALSE. Even small businesses use market data (e.g., looking at local competitor pricing or changes in local demographics) to adjust their marketing mix."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:42bd7cb1', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "If a product uses digital distribution, it might allow the business to charge a lower price due to reduced overhead costs."}'::jsonb, '{"answer": true, "explain": "TRUE. This is a perfect example of an integrated mix. Digital distribution (Place) has no shop rent or transport costs, allowing a reduction in Price."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:e14b1272', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "A business should immediately stop production of a product if market data shows sales fell for one month."}'::jsonb, '{"answer": false, "explain": "FALSE. A business must look at long-term trends. A one-month drop could just be seasonal or due to a competitor''s short-term promotion."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tf:b7713bab', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "When starting a new local business, social media is an excellent promotional tool because it can target specific demographics cheaply."}'::jsonb, '{"answer": true, "explain": "TRUE. For a new business (like Beth''s playball centre), targeted social media keeps costs low while directly reaching the target market (young parents)."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:8c490cb0', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "The Integrated Marketing Mix", "reading": "<p>The elements of the marketing mix (Product, Price, Place, Promotion) must work and fit together. If they do not complement each other, the product is unlikely to be successful. This is called an <strong>Integrated Marketing Mix</strong>.</p>\n  <p>If a business wants to increase sales, the mix must be coordinated:</p>\n  <ul>\n  <li><strong>Price:</strong> Must be at a level to attract the target market but also reflect the product''s quality.</li>\n  <li><strong>Product:</strong> Does the product justify the price? (e.g., A brand new tech model can justify a higher price than an older model).</li>\n  <li><strong>Place:</strong> The distribution channel affects the price. If a product is distributed digitally (no physical transport costs), the price can potentially be lower.</li>\n  <li><strong>Promotion:</strong> Customers need to know about the product. The advertising media chosen must target the specific people who want the product and can afford the price.</li>\n  </ul>\n  <div class=\"case-study-box\">\n  <h4>Example of a POOR Marketing Mix</h4>\n  <p>A business develops a highly premium, expensive new bottled soft drink (<em>Product/Price</em>). However, it is only sold online with no supermarket availability (<em>Place</em>), and it is advertised in teen magazines where the readers cannot afford it (<em>Promotion</em>). This sends a confused message and will fail.</p>\n  </div>", "question": "What does it mean for a business to have an ''integrated marketing mix''?", "options": ["The business spends equal money on each of the 4 Ps", "The 4Ps work together and complement each other", "The business focuses only on price and product", "The business changes its price every month"]}'::jsonb, '{"answer": 1, "explain": "An integrated mix means Product, Price, Place and Promotion must all fit together and send a consistent message, or the product is unlikely to succeed."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:af02c823', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: The Nintendo Switch", "reading": "<p>A highly successful integrated marketing mix ensures that different elements complement each other. The <strong>Nintendo Switch</strong> is a perfect example:</p>\n  <ul>\n  <li><strong>Product:</strong> A games console with innovative controllers allowing players to take their gaming outside the home (highly portable).</li>\n  <li><strong>Price:</strong> Launched at £279.99. Nintendo used a <em>Price Skimming</em> strategy, setting the launch price higher than some competitors because of its unique innovation.</li>\n  <li><strong>Place:</strong> Sold through usual physical retail outlets and digital downloads. Initial physical supplies were deliberately restricted, creating a shortage (a technique Nintendo often uses to increase demand).</li>\n  <li><strong>Promotion:</strong> Advertisements heavily focused on the portability of the system within social settings, perfectly complementing the unique feature of the <em>Product</em>.</li>\n  </ul>", "question": "Why did Nintendo use price skimming when launching the Switch at £279.99?", "options": ["To match the cheapest price of competitors", "To sell below cost and gain market share quickly", "To set a higher price because of its unique features", "To offer bulk discounts to major retailers"]}'::jsonb, '{"answer": 2, "explain": "The card explains Nintendo used a Price Skimming strategy, setting the launch price higher than some competitors because of its unique innovation."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:cc783c0d', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "Interpreting Market Data", "reading": "<p><strong>Market Data</strong> is information that can help a business make marketing decisions. Businesses use this data (such as changes in demand or competitor sales) to adjust their integrated marketing mix.</p>\n  <p><strong>Key Formulas & Concepts:</strong></p>\n  <ul>\n  <li><strong>Target Market:</strong> The specific group of consumers to whom the business tries to sell its products.</li>\n  <li><strong>Market Share:</strong> The percentage of total sales in a whole market that one single business has made.</li>\n  <li><strong>Market Growth:</strong> The percentage increase in the size of the overall market.</li>\n  </ul>\n  <div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business / Total sales in the market) &times; 100<br><br>\n  <strong>Market Growth (%) =</strong> ((New Market Size - Original Market Size) / Original Market Size) &times; 100\n  </div>", "question": "How is Market Share (%) calculated?", "options": ["((New Market Size - Original Size)/Original Size) x 100", "(Total market sales / Business sales) x 100", "(Profit / Total Sales) x 100", "(Sales of the business / Total sales in the market) x 100"]}'::jsonb, '{"answer": 3, "explain": "The formula box states Market Share (%) = (Sales of the business / Total sales in the market) x 100."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:3cd0d615', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "The Market Share Trap (LXFridges)", "reading": "<p>Students often assume that if a business''s sales increase, its market share must also increase. <strong>This is false.</strong></p>\n  <div class=\"case-study-box\">\n  <h4>Case Study: LXFridges</h4>\n  <p>In 2014, LXFridges sold 120,000 fridges. The total fridge market was 500,000. <br><em>(Market Share = 24%)</em></p>\n  <p>In 2016, LXFridges sold 145,200 fridges. The total fridge market grew to 720,000. <br><em>(Market Share = 20.1%)</em></p>\n  </div>\n  <p><strong>Analysis:</strong> Although LXFridges sold 25,200 <em>more</em> fridges (a 21% increase), the total market grew much faster (by 44%). Because competitors grew faster than LXFridges, LXFridges actually <strong>lost market share</strong>. To respond to this market data, LXFridges must review its marketing mix (e.g., improve the product or increase promotion) to catch up with competitors.</p>", "question": "LXFridges'' sales rose 21% (120,000 to 145,200), yet its market share fell from 24% to 20.1%. What explains this?", "options": ["The total market grew even faster (44%) than sales did", "LXFridges actually lost customers overall", "The formula for market share was calculated incorrectly", "Market share can only fall when a business''s sales fall too"]}'::jsonb, '{"answer": 0, "explain": "The card shows that although LXFridges'' sales increased, the total market grew by 44% versus LXFridges'' 21%, so competitors outgrew them and LXFridges lost market share."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:7ebdcaf5', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "Interpreting Long-Term Data Trends", "reading": "<p>When reviewing market data (like customer preference surveys), businesses must look at long-term trends before taking drastic action.</p>\n  <p><strong>Chocolate Preference Data (2014 to 2016):</strong><br>\n  A survey of 5,000 people showed ''Fruit and Nut'' steadily increasing in popularity over three years. However, ''Plain Milk Chocolate'' spiked in 2015 and then dropped significantly in 2016.</p>\n  <p><strong>How should the business respond?</strong><br>\n  There will always be slight changes in the popularity of a product. A drop in one year could be the result of a competitor running a massive promotion, rather than customers suddenly disliking milk chocolate. A business must view data against a longer-term view before making drastic, expensive decisions to cut production or change a product entirely.</p>", "question": "Plain Milk Chocolate sales spiked in 2015 then dropped in 2016. What should the business do before taking drastic action?", "options": ["Immediately stop producing the product that dipped", "Look at a longer-term trend, not one year''s dip", "Assume customers permanently dislike the product", "Cut the price to zero to clear stock"]}'::jsonb, '{"answer": 1, "explain": "The card warns that a one-year drop could be caused by a competitor''s promotion, so a business must view data against a longer-term trend before making drastic, expensive decisions."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:learn:322ed16b', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'learn', 'mcq', 1, '{"readingTitle": "Activity: Devising a Marketing Mix", "reading": "<p><strong>Beth''s Playball Centre</strong></p>\n  <p>Beth is opening a playball centre targeting children aged 2 to 12. She used market data and the integrated marketing mix to plan her launch:</p>\n  <ul>\n  <li><strong>Promotion:</strong> Social media is ideal. Her target market is young parents (who pay the entry fee), and they are heavy users of Facebook/Instagram. This keeps costs low for a new business.</li>\n  <li><strong>Product:</strong> She needs ball-play areas for children, but also a cafe/waiting area for parents. This adds value and creates a secondary revenue stream.</li>\n  <li><strong>Price:</strong> She could use penetration pricing (or opening offers like \"5th visit free\") to tempt parents away from established local competitors until her brand is known.</li>\n  <li><strong>Place/Extension:</strong> She can hire the entire centre out for private birthday parties. This guarantees a set income and acts as a promotional tool when invited children visit the centre for the first time.</li>\n  </ul>", "question": "Why is social media an especially good promotional choice for Beth''s Playball Centre?", "options": ["It is the only legal form of advertising for children''s businesses", "It guarantees a business can charge higher prices", "Young parents (her target market) use it heavily, cutting costs", "It removes the need for a marketing mix altogether"]}'::jsonb, '{"answer": 2, "explain": "The card states Beth''s target market is young parents who are heavy users of Facebook/Instagram, so social media keeps costs low for her new business."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:misc:a9f6a28e', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students assume that increasing sales automatically means increasing market share.</p><p><strong>✅ The correct idea:</strong> This is a massive trap in data interpretation questions. If LXFridges increases sales by 20%, but the total market grows by 40%, LXFridges'' market share has actually HALVED because competitors grew faster.</p>", "question": "If a business''s sales increase but the total market grows even faster, what happens to its market share?", "options": ["It automatically rises because sales are up", "It stays exactly the same regardless of market changes", "It becomes impossible to calculate", "It can fall if competitors grow faster than the business"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that rising sales always mean rising market share — if the market grows faster than the business, its share can actually fall."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:misc:fd850293', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''Integrated Marketing Mix'' means spending exactly the same amount of money on all 4 Ps.</p><p><strong>✅ The correct idea:</strong> Integration has nothing to do with budget equality. It means the 4 Ps send a CONSISTENT MESSAGE. A high-end product needs a high price, an exclusive place, and premium promotion.</p>", "question": "What does an ''Integrated Marketing Mix'' actually require?", "options": ["The 4 Ps sending a consistent message, e.g. a high-end product having a high price", "Spending exactly the same amount of money on Product, Price, Place and Promotion", "Only using Price and Promotion while ignoring Product and Place", "Changing the marketing mix every financial year regardless of data"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that integration means equal budgets — it actually means the 4 Ps send a consistent message."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:misc:4ec2d5e9', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In 9-mark questions about market data, students just copy numbers from the table without manipulating them.</p><p><strong>✅ The correct idea:</strong> To score high analysis marks, you MUST manipulate the data. Don''t just say ''Sales went from 120k to 145k''. Say ''Sales increased by 25,200, which is a 21% increase, but the market grew by 44%''. Calculate the differences!</p>", "question": "In a data-response question, how should a student use the figures in a table to earn analysis marks?", "options": ["Simply copy the numbers exactly as given in the table", "Manipulate the data by calculating percentage changes", "Ignore the table and rely on general knowledge instead", "Round all figures to the nearest 100,000 before answering"]}'::jsonb, '{"answer": 1, "explain": "The card states students must manipulate the data (e.g. calculate the 21% sales increase vs the 44% market growth) rather than just copying numbers."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:misc:5baee1fa', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students recommend drastic actions (like closing a factory) based on a slight dip in data.</p><p><strong>✅ The correct idea:</strong> Always evaluate the need for a ''long-term view''. A slight dip in chocolate sales in one year does not mean the product is dead; it could be due to a short-term competitor promotion.</p>", "question": "What should students do before recommending a drastic action (like closing a factory) based on a data dip?", "options": ["Recommend the drastic action immediately since the data proves it is necessary", "Assume the dip will continue permanently into future years", "Evaluate the figures against a longer-term trend, not just a single short-term dip", "Ignore the dip completely and change nothing about the marketing mix"]}'::jsonb, '{"answer": 2, "explain": "The card stresses evaluating the need for a ''long-term view'', since a slight dip could be caused by a short-term competitor promotion rather than lasting decline."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tips:f680911a', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tips', 'mcq', 1, '{"readingTitle": "Formula (Quantitative Skills) — Calculating Market Share & Growth", "reading": "<p>You must memorise these two formulas for data interpretation questions:</p>\n  <p><strong>Market Share (%) =</strong> (Sales of the business / Total sales in the market) &times; 100</p>\n  <p><strong>Market Growth (%) =</strong> ((New Market Size - Original Size) / Original Size) &times; 100</p>", "question": "Which formula correctly calculates Market Growth (%)?", "options": ["(Sales of the business / Total sales in the market) x 100", "((New Market Size - Original Size) / Original Size) x 100", "(New Market Size / Sales of business) x 100", "(Original Size - New Market Size) / New Market Size x 100"]}'::jsonb, '{"answer": 1, "explain": "The card gives the exact formula: Market Growth (%) = ((New Market Size - Original Size) / Original Size) x 100."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tips:32be4468', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (9 marks) — Structuring a 9-Mark Recommendation", "reading": "<p>For the massive 9-mark questions (like Joe Allen or 2wheels Ltd), follow this exact structure:</p>\n  <ul>\n  <li><strong>K & U:</strong> Define the marketing concept/method and state an advantage.</li>\n  <li><strong>APP:</strong> Make TWO separate applied points using context (e.g., the specific target market, or calculating data from a table).</li>\n  <li><strong>AN:</strong> Explain the business impact (e.g., increased revenue, reduced costs) for BOTH points.</li>\n  <li><strong>EVAL:</strong> State a clear decision (Judgement) and back it up with a strong reason drawn from the case study (Justification).</li>\n  </ul>", "question": "In a 9-mark evaluation answer, what does the ''APP'' stage of the structure require?", "options": ["A dictionary definition of the key term with no context", "A final judgement backed by justification", "A single one-word answer with no explanation", "Two separate applied points using specific case context"]}'::jsonb, '{"answer": 3, "explain": "The card''s structure defines APP as making two separate applied points using context, such as the specific target market or calculated data."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:tips:2e1eb43b', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tips', 'mcq', 1, '{"readingTitle": "Analysis Trick — The Market Data Trap", "reading": "<p>If an exam question gives you a table showing a business''s sales increasing, immediately check the ''Total Market'' figures.</p>\n  <p>Examiners love to trick you into saying \"the business is doing well because sales are up\". If the total market is growing faster than the business, their market share is dropping, which is a massive <strong>negative</strong> point for analysis.</p>", "question": "If exam data shows a business''s sales rising, what must a student check before concluding the business is ''doing well''?", "options": ["Whether the total market is growing even faster than the business", "Whether the business''s logo or branding has changed", "Whether the business operates online or in a physical store", "Whether the sales figures are presented in pounds or in units"]}'::jsonb, '{"answer": 0, "explain": "The card warns examiners trick students into praising rising sales alone — you must check if the total market grew even faster, meaning market share actually fell."}'::jsonb),
